export type AppView = 'landing' | 'catalog' | 'previewer';

import { GoogleGenAI } from "@google/genai";

export async function applyMaterialToPhoto(personPhotoBase64: string, materialPhotoUrl: string, materialName: string): Promise<string | null> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // We need the material image as base64 too if we want Gemini to see its texture accurately.
  // For this demo, we'll fetch the material and convert it, or just describe it.
  // Using gemini-2.5-flash-image for visual editing.

  try {
    const materialResponse = await fetch(materialPhotoUrl);
    const materialBlob = await materialResponse.blob();
    const materialBase64 = await blobToBase64(materialBlob);

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: personPhotoBase64.split(',')[1],
              mimeType: 'image/jpeg',
            },
          },
          {
            inlineData: {
              data: materialBase64.split(',')[1],
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `This is a high-fidelity virtual try-on task. 
            Image 1: A person wearing clothes.
            Image 2: A fabric material swatch called "${materialName}".
            Task: Replace the material of the top/shirt/clothing worn by the person in Image 1 with the exact fabric pattern, texture, and color shown in Image 2. 
            Maintain all original folds, shadows, lighting, and fit of the clothing. The person's face, hair, and background must remain identical.`,
          },
        ],
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
}

function blobToBase64(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

import React, { useState, useEffect } from 'react';
import { Material, User, AppView } from './types';
import { FABRIC_MATERIALS } from './constants';
import Header from './components/Header';
import MaterialCatalog from './components/MaterialCatalog';
import ImagePreviewer from './components/ImagePreviewer';
import LandingPage from './components/LandingPage';
import AuthModal from './components/AuthModal';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('landing');
  const [user, setUser] = useState<User | null>(null);
  const [selectedMaterial, setSelectedMaterial] = useState<Material | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);

  const handleMaterialSelect = (material: Material) => {
    setSelectedMaterial(material);
    if (!user) {
      setShowAuthModal(true);
    } else {
      setView('previewer');
    }
  };

  const handleLogin = (email: string) => {
    setUser({
      name: email.split('@')[0],
      email: email,
      isLoggedIn: true
    });
    setShowAuthModal(false);
    if (selectedMaterial) {
      setView('previewer');
    } else {
      setView('catalog');
    }
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header 
        user={user} 
        setView={setView} 
        onLogout={() => { setUser(null); setView('landing'); }}
        onLoginClick={() => setShowAuthModal(true)}
      />

      <main className="flex-grow">
        {view === 'landing' && (
          <LandingPage onGetStarted={() => setView('catalog')} />
        )}

        {view === 'catalog' && (
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
            <h2 className="text-3xl font-display font-bold text-slate-900 mb-8">Premium Fabric Collection</h2>
            <MaterialCatalog 
              materials={FABRIC_MATERIALS} 
              onSelect={handleMaterialSelect} 
            />
          </div>
        )}

        {view === 'previewer' && (
          <ImagePreviewer 
            selectedMaterial={selectedMaterial} 
            onBack={() => setView('catalog')}
          />
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center space-y-4 md:space-y-0">
          <div className="flex items-center space-x-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">FV</div>
            <span className="text-slate-900 font-bold">FabricVision</span>
          </div>
          <div className="text-slate-500 text-sm">
            © 2024 FabricVision SaaS. Empowering material sellers worldwide.
          </div>
          <div className="flex space-x-6 text-slate-400">
            <a href="#" className="hover:text-indigo-600 transition-colors">Privacy</a>
            <a href="#" className="hover:text-indigo-600 transition-colors">Terms</a>
            <a href="#" className="hover:text-indigo-600 transition-colors">Contact</a>
          </div>
        </div>
      </footer>

      {showAuthModal && (
        <AuthModal 
          onClose={() => setShowAuthModal(false)} 
          onLogin={handleLogin} 
        />
      )}
    </div>
  );
};

export default App;

